package main

import (
	"fmt"
	"mime"
	"net/http"
	"os"
	"path/filepath"
	"strings"
)

func uploadFileHandler(uploadsDir string) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		filename := r.URL.Query().Get("filename")
		if filename == "" {
			http.Error(w, "filename is required", http.StatusBadRequest)
			return
		}

		filename = filepath.Base(filename)
		if filename == "." || filename == "/" || filename == string(filepath.Separator) {
			http.Error(w, "invalid filename", http.StatusBadRequest)
			return
		}

		fullPath := filepath.Join(uploadsDir, filename)

		cleanUploadsDir, err := filepath.Abs(uploadsDir)
		if err != nil {
			http.Error(w, "server error", http.StatusInternalServerError)
			return
		}
		cleanFullPath, err := filepath.Abs(fullPath)
		if err != nil {
			http.Error(w, "server error", http.StatusInternalServerError)
			return
		}

		if !strings.HasPrefix(cleanFullPath, cleanUploadsDir+string(filepath.Separator)) && cleanFullPath != cleanUploadsDir {
			http.Error(w, "invalid file path", http.StatusBadRequest)
			return
		}

		f, err := os.Open(cleanFullPath)
		if err != nil {
			if os.IsNotExist(err) {
				http.Error(w, "file not found", http.StatusNotFound)
				return
			}
			http.Error(w, "failed to open file", http.StatusInternalServerError)
			return
		}
		defer f.Close()

		fi, err := f.Stat()
		if err != nil {
			http.Error(w, "failed to stat file", http.StatusInternalServerError)
			return
		}
		if fi.IsDir() {
			http.Error(w, "not a file", http.StatusBadRequest)
			return
		}

		ext := strings.ToLower(filepath.Ext(cleanFullPath))
		if ext != "" {
			if ct := mime.TypeByExtension(ext); ct != "" {
				w.Header().Set("Content-Type", ct)
			} else {
				w.Header().Set("Content-Type", "application/octet-stream")
			}
		} else {
			w.Header().Set("Content-Type", "application/octet-stream")
		}

		w.Header().Set("Content-Disposition", fmt.Sprintf(`inline; filename="%s"`, filepath.Base(cleanFullPath)))
		w.Header().Set("Content-Length", fmt.Sprintf("%d", fi.Size()))

		http.ServeContent(w, r, filepath.Base(cleanFullPath), fi.ModTime(), f)
	}
}